/** Subset kỳ kế toán — `GET /accounting/periods` (Tạm ứng, phiếu thu/chi, …). */
export interface AccountingPeriodDateGate {
  year: number;
  month: number;
  status: string;
}

export const BR001_PERIOD_EDIT_MESSAGE =
  'Không nhập/sửa chứng từ trong kỳ đã khóa hoặc đóng sổ (BR-001)';

function parseCalendarMonthYear(dateStr: string): { year: number; month: number } | null {
  if (!dateStr?.trim()) return null;
  const dateOnly = dateStr.trim().slice(0, 10);
  const [yearStr, monthStr] = dateOnly.split('-');
  const year = Number(yearStr);
  const month = Number(monthStr);
  if (!year || !month) return null;
  return { year, month };
}

/** BR-001 — validate khi user Lưu (ngày từ ô date / datetime-local, lịch user). */
export function validateVoucherDateAgainstPeriods(
  voucherDate: string,
  periods: AccountingPeriodDateGate[],
): string | null {
  if (!voucherDate || periods.length === 0) return null;
  const parts = parseCalendarMonthYear(voucherDate);
  if (!parts) return null;
  const { year, month } = parts;

  const period = periods.find(p => p.year === year && p.month === month);
  if (period && (period.status === 'Locked' || period.status === 'Closed')) {
    return BR001_PERIOD_EDIT_MESSAGE;
  }
  return null;
}
